parameters.text:
=You are checking for duplicate GitHub issues. Be fast and concise.

Existing open issue titles:
{{ $input.all().filter(i => !i.json.pull_request).map(i => i.json.title).join('\n') }}

Planning notes (new issues to be created from this):
{{ $('Planning Notes Input').first().json.planningNotes }}

For each topic mentioned in the planning notes, check if a similar issue already exists in the list above. Two issues are duplicates if they are about the same component and the same problem/feature — even if worded differently.

Respond ONLY with a valid JSON object — no markdown, no extra text:
{"duplicates": ["exact topic or short phrase from planning notes that already exists"], "new": ["exact topic or short phrase from planning notes that does NOT exist yet"]}

parameters.jsCode:
const item = $input.first();
const raw = item.json.output || item.json.text || item.json.message || '';

let issues = [];
try {
  const cleaned = raw.replace(/```json?\s*/g, '').replace(/```\s*/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    issues = parsed;
  } else if (parsed.issues && Array.isArray(parsed.issues)) {
    issues = parsed.issues;
  } else {
    throw new Error('Expected an array');
  }
} catch (e) {
  throw new Error(`Failed to parse AI output: ${e.message}\n\nRaw: ${raw.substring(0, 500)}`);
}

// Get the existing titles fetched earlier
const existingTitles = $('Extract Existing Titles').first().json.existingTitles || [];

const validated = issues.map((issue, i) => {
  if (!issue.title || typeof issue.title !== 'string') {
    throw new Error(`Issue at index ${i} is missing a valid title`);
  }
  let label = issue.label || issue.labels || 'chore';
  if (Array.isArray(label)) label = label[0] || 'chore';
  label = String(label).trim();

  // Duplicate check — normalize and compare titles
  const normalize = t => t.toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, ' ').trim();
  const newTitle = normalize(issue.title);
  const isDuplicate = existingTitles.some(existing => {
    const existingNorm = normalize(existing);
    // Exact match or one contains the other (catches minor wording differences)
    return existingNorm === newTitle ||
      existingNorm.includes(newTitle) ||
      newTitle.includes(existingNorm);
  });

  return {
    title: issue.title.trim(),
    body: issue.body || '',
    label,
    assignee: issue.assignee || null,
    isDuplicate,
    duplicateReason: isDuplicate ? `Similar to existing: "${existingTitles.find(e => normalize(e).includes(newTitle) || newTitle.includes(normalize(e)))}"` : null
  };
});

return validated.map(issue => ({ json: issue }));

// Collect results from both branches after loop completes
const items = $input.all();
const created = [];
const skipped = [];

for (const item of items) {
  if (item.json.html_url) {
    // Successfully created
    created.push({ number: item.json.number, title: item.json.title, url: item.json.html_url });
  } else if (item.json.isDuplicate) {
    // Skipped as duplicate
    skipped.push({ title: item.json.title, reason: item.json.duplicateReason });
  }
}

console.log(`Created: ${created.length}, Skipped (duplicates): ${skipped.length}`);
return [{ json: { created, skipped, createdCount: created.length, skippedCount: skipped.length } }];
